/**
* Experimental "farbrausch V2" backend based on "modern" AudioWorkletNode infrastructure.
*
* version 0.1
*
* Copyright (C) 2023 Juergen Wothke
*
*
* The code in this "processor" has not been automatically built but patched together manually 
* based on the WASM code built for my regular ScriptProcessorNode based "V2" backend. If respective
* "modern" intrastructure were to be used seriously then this file would obvisouly need to be 
* built via a respective automatic build script.
*
* There are 4 parts in this file (see "part .. start" comments):
*
* - part 1: additional glue code needed to make the "original" Emscripten generated code happy
* - part 2: the original Emscripten generated WASM file - base64 encoded into a string. Loading additional
*           WASM files from the "processor" isn't possible so this "inlining" hack
*           seems to be necessary. trade-offs: additional base64 encoding support must be available
*           in the build-tool; the transferred file will be 33% larger than the normal "*.wasm" file
* - part 3: the original Emscripten Module generated for my old ScriptProcessorNode based backend (with added
*           "	wasmBinary: intArrayFromBase64(wasm64)," entry so that Emscripten doesn't try to load the 
*           WASM file but instead directly uses the supplied binary)
* - part 4: a rudimentary AudioWorkletProcessor implementation that uses the above WASM code (if different 
*           backends where to be supported in the future, then the generic reusable parts would need to be 
*           identified such that a higher abstraction level base class could be provided to ease the 
*           development of these backends.. that base class would have to handle most of those
*           features that have not been implemented in the current "proof of concept").
*
* note: It seems that current Web browsers fail to properly reload this "processor" file - and it
* has to be renamed each time a change is made.. I havn't seen such a bad joke infrastructure in 
* a long time!
*
* note: In spite of being inlined the actual WASM code loading is still asynchronous and the respective
* Emscripten module is not immediately in a usable state, i.e. neither is the "processor" after it
* has supposedly been loaded. This means that at the time that the respective "node" is created the used
* "processor" may or may not be in a usable state yet, i.e. the "usable" state of the basic node/processor
* configuration has to be assertained using asynchronous messaging via additional application code.
* (Apparently it is too much to ask that the "processor load" should actually make sure that the 
* "processor" code is actually ready to be used. what a pathetic MickeyMouse infrastructure!)
*
* note: it seems that iOS Safari does not support private methods in the version 
* that still seems to be prevalent on older iPads (so that feature should 
* not be used yet to avoid unecessarily breaking stuff for those users)
*/

/////////////////////////////// part 1 start /////////////////////////////////////////

var window = {};
var document = {
	currentScript: {
		src: "-"
	},
	title: "foobar",
};

// Copied from https://github.com/strophe/strophejs/blob/e06d027/src/polyfills.js#L149

// This code was written by Tyler Akins and has been placed in the
// public domain.  It would be nice if you left this header intact.
// Base64 code from Tyler Akins -- http://rumkin.com

/**
 * Decodes a base64 string.
 * @param {string} input The string to decode.
 */
var decodeBase64 = typeof atob == 'function' ? atob : function (input) {
  let keyStr = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/=';

  let output = '';
  let chr1, chr2, chr3;
  let enc1, enc2, enc3, enc4;
  let i = 0;
  // remove all characters that are not A-Z, a-z, 0-9, +, /, or =
  input = input.replace(/[^A-Za-z0-9\+\/\=]/g, '');
  do {
    enc1 = keyStr.indexOf(input.charAt(i++));
    enc2 = keyStr.indexOf(input.charAt(i++));
    enc3 = keyStr.indexOf(input.charAt(i++));
    enc4 = keyStr.indexOf(input.charAt(i++));

    chr1 = (enc1 << 2) | (enc2 >> 4);
    chr2 = ((enc2 & 15) << 4) | (enc3 >> 2);
    chr3 = ((enc3 & 3) << 6) | enc4;

    output = output + String.fromCharCode(chr1);

    if (enc3 !== 64) {
      output = output + String.fromCharCode(chr2);
    }
    if (enc4 !== 64) {
      output = output + String.fromCharCode(chr3);
    }
  } while (i < input.length);
  return output;
};

// Converts a string of base64 into a byte array.
// Throws error on invalid input.
function intArrayFromBase64(s) {
  try {
    let decoded = decodeBase64(s);
    let bytes = new Uint8Array(decoded.length);
    for (let i = 0 ; i < decoded.length ; ++i) {
      bytes[i] = decoded.charCodeAt(i);
    }
    return bytes;
  } catch (_) {
    throw new Error('Converting base64 string to bytes failed.');
  }
}

/////////////////////////////// part 1 end /////////////////////////////////////////


/////////////////////////////// part 2 start /////////////////////////////////////////
var wasm64 = '';
/////////////////////////////// part 2 end /////////////////////////////////////////


/////////////////////////////// part 3 start /////////////////////////////////////////

// create separate namespace for all the Emscripten stuff.. otherwise naming clashes may occur especially when 
// optimizing using closure compiler..
window.spp_backend_state_V2M= {
	wasmBinary: intArrayFromBase64(wasm64),
	notReady: true,	
	adapterCallback: function(){}	// overwritten later	
};
window.spp_backend_state_V2M["onRuntimeInitialized"] = function() {	// emscripten callback needed in case async init is used (e.g. for WASM)
	this.notReady= false;
	
	this.adapterCallback();
}.bind(window.spp_backend_state_V2M);	

