/**
* Minimalistic "farbrausch V2" processor implementation that provides basic audio playback
* and scope data streaming functionality.
*
* FIXME: most of the features available in the old ScriptProcessorNode based backends
* have not been implemented yet, e.g. support for backends that produce buffer sizes 
* other than 128, resampling, stereo panning, startup silence skipping, 
* playtime timeout, support for backends that produce mono, 
* trial&error file loading of required additional files, etc
*/
class V2MProcessor extends AudioWorkletProcessor {
	constructor() {
	    super();

		this.Module = backend_V2M.Module;
				
		this.port.onmessage = this.handleMessage.bind(this);
		
		this.ready = false;
		this.paused = true;
		this.sampleRate = 0;
		
		// shared buffers see same vars in WorkerBackend
		
		this.scopeDoubleBufferToggle = 0;
		
		this.scopeBuffers = [];
		this.scopeBuffers.push([]);
		this.scopeBuffers.push([]);

		this.scopeBuffersFloat32View = this.makeScopeFloat32View(this.scopeBuffers);
		
		// issue: in this garbage model the WASM code may not actually be ready at this point.
		// interestingly this problem does not strike that often while testing locally, but 
		// it seems to happen regularly while loading the page remotely .. what a POS!
	}
	
	setSharedVar(v, val) {
		const int32 = new Int32Array(v);
		int32[0] = val;
	}
	
	getSharedVar(v) {
		const int32 = new Int32Array(v);
		return int32[0];
	}

	makeScopeFloat32View(bufs) {	// redundant to same code on UI thread side
		let n = bufs[0].length;
		
		let root = [];
		let bufs1 = [];
		let bufs2 = [];
		for (let i = 0; i<n; i++) {
			bufs1.push( new Float32Array(bufs[0][i]));
			bufs2.push( new Float32Array(bufs[1][i]));
		}
		root.push(bufs1);
		root.push(bufs2);
		
		return root;		
	}
	
	handleMessage(event) {
		let d = event.data;
		let type = d.message;
		
		// updates in the SharedArrayBuffer "ret" should "eventually" propagate back to 
		// the UI thread so it might be possible to "busy wait" for these updates
		// in the UI thread		
		let sab = d.ret;
		
		switch(type) {
			case 'getWasmReadyConfirmation':
				this.getWasmReadyConfirmation();	
				break;
				
			case 'loadMusicData':
				this.loadMusicData(d.sampleRate, d.path, d.filename, d.data, d.options, sab);
				break;
				
			case 'evalTrackOptions':
				this.evalTrackOptions(d.options, sab);
				break;
			
			case 'pause':
				this.pause(sab);
				break;
			
			case 'play':
				this.play(sab);
				break;
			
			case 'teardown':
				this.teardown(sab);
				break;
			
			case 'getNumberTraceStreams':
				this.getNumberTraceStreams(sab);
				break;
			
			case 'setSharedScopeBuffers':
				this.setSharedScopeBuffers(d.scopeBuffers, sab);
				break;
			case 'probeDuration':
				// Run async so it doesn't block the message handler or process()
				this.probeDurationAsync(d.filename, d.data, d.sampleRate, d.reqId);
				break;

			default: 
				console.log("error: unsupported message received from node: " + type);
		}; 		
	}
	
	
	getWasmReadyConfirmation() {
		if (this.Module.notReady) {
			// seems at this poiht the WASM setup hasn't completed yet
						
			this.Module.adapterCallback = function() {
				console.log("WASM was ready eventually");
				
				this.port.postMessage({message: 'wasmReady'});				
				this.Module.adapterCallback = function() {};
			}.bind(this);
		} 
		else {
			console.log("WASM was ready immediately");
			this.port.postMessage({message: 'wasmReady'});
		}
	}
	
	isAdapterReady() {
		return !this.Module.notReady;
	}
	
	teardown(sab) {
		this.Module.ccall('emu_teardown', 'number');	// just in case
		this.paused = true;
		this.ready  = false;
		this._silenceStarttime = -1;
		this._currentPlaytime  = 0;
		
		this.setReturnCode(sab, 0);	
	}
	
	pause(sab) {
		this.paused = true;
		
		this.setReturnCode(sab, 0);	
	}
	play(sab) {
		this.paused = false;
		
		this.setReturnCode(sab, 0);	
	}
	
	setReturnCode(sab, ret) {
		const int32 = new Int32Array(sab);
		Atomics.store(int32, 0, ret);		// this should wake up the UI thread..
		Atomics.notify(int32, 0, 1);	// useless since UI thread cannot use wait API
	}
	
	loadMusicData(sampleRate, path, filename, data, options, sab) {
		this._silenceStarttime= -1;
		this._silenceTimeout= 5; // by default 5 secs of silence will end a song
		this._currentPlaytime= 0;	// reset for accurate duration measurement
		
		this.sampleRate = sampleRate;
		
		this.ready = false;
		
		var buf = this.Module._malloc(data.length);
		this.Module.HEAPU8.set(data, buf);
		var ret = this.Module.ccall('emu_load_file', 'number', ['string', 'number', 'number', 'number', 'number'], [filename, buf, data.length, sampleRate, 128]);
		this.Module._free(buf);
		
		this.setReturnCode(sab, ret);	
	}
	
	evalTrackOptions(options, sab) {		
		var id= (options && options.track) ? options.track : -1;	// by default do not set track
		
		var ret=  this.Module.ccall('emu_set_subsong', 'number', ['number', 'number'], [id, this._scopeEnabled]);

		if (!ret) {
			this.ready = true;
		}
	
		this.setReturnCode(sab, ret);	
	}

/////////////////// access to data from the actual backend impl /////////////////////	
	
	
	computeAudioSamples() {
		return this.Module.ccall('emu_compute_audio_samples', 'number');
	}
	getAudioBuffer() {
		var ptr=  this.Module.ccall('emu_get_audio_buffer', 'number');			
		// make it a this.Module.HEAP16 pointer
		return ptr >> 1;	// 2 x 16 bit samples			
	}
	getAudioBufferLength() {
		var len= this.Module.ccall('emu_get_audio_buffer_length', 'number');
		return len;
	}	
	
	
	// FIXME below not connected to frontend yet
	/* Probe duration without blocking process() or the main thread.
	   Runs the WASM decoder in a chunked loop via setTimeout, replies
	   via postMessage when done. reqId ties the reply to the caller's Promise. */
	probeDurationAsync(filename, data, sampleRate, reqId) {
		// Don't probe while a real song is playing — would corrupt WASM state
		if (!this.paused) {
			this.port.postMessage({ message: 'probeDurationResult', reqId: reqId, ms: 0 });
			return;
		}

		var buf = this.Module._malloc(data.length);
		this.Module.HEAPU8.set(data, buf);
		var loadRet = this.Module.ccall('emu_load_file', 'number',
			['string','number','number','number','number'],
			[filename, buf, data.length, sampleRate, 128]);
		this.Module._free(buf);

		if (loadRet !== 0) {
			this.port.postMessage({ message: 'probeDurationResult', reqId: reqId, ms: 0 });
			return;
		}

		var subRet = this.Module.ccall('emu_set_subsong', 'number', ['number','number'], [-1, 0]);
		if (subRet !== 0) {
			this.Module.ccall('emu_teardown', 'number');
			this.port.postMessage({ message: 'probeDurationResult', reqId: reqId, ms: 0 });
			return;
		}

		// Synchronous loop — setTimeout unavailable in AudioWorkletGlobalScope
		var playTime = 0;
		var silStart = -1;
		var silLimit = 5 * sampleRate;
		var maxLimit = 3600 * sampleRate;
		var duration = 0;

		while (playTime < maxLimit) {
			var r = this.Module.ccall('emu_compute_audio_samples', 'number');
			if (r !== 0) { duration = playTime; break; }

			var len = this.Module.ccall('emu_get_audio_buffer_length', 'number');
			var ptr = this.Module.ccall('emu_get_audio_buffer', 'number') >> 1;
			var sum = 0;
			for (var j = 0; j < len * 2; j++) sum += Math.abs(this.Module.HEAP16[ptr + j]);
			playTime += len;

			if (sum === 0) {
				if (silStart < 0) silStart = playTime;
				if (playTime - silStart >= silLimit) { duration = silStart; break; }
			} else {
				silStart = -1;
			}
		}
		if (!duration) duration = playTime;

		this.Module.ccall('emu_teardown', 'number');
		this.ready  = false;
		this.paused = true;

		var ms = Math.round(duration / sampleRate * 1000);
		this.port.postMessage({ message: 'probeDurationResult', reqId: reqId, ms: ms });
	}

		getMaxPlaybackPosition() { 
		if (!this.isAdapterReady()) return -1;
		return this.Module.ccall('emu_get_max_position', 'number');
	}
	getPlaybackPosition() {
		if (!this.isAdapterReady()) return -1;
		return this.Module.ccall('emu_get_current_position', 'number');
	}
	seekPlaybackPosition(pos) {
		if (!this.isAdapterReady()) return;
		this.Module.ccall('emu_seek_position', 'number', ['number'], [pos]);
	}

	setSharedScopeBuffers(bufs, sab) {
		this.scopeDoubleBufferToggle = 0;
		this.scopeBuffers = bufs;
		this.scopeBuffersFloat32View = this.makeScopeFloat32View(this.scopeBuffers);
			
		this.setReturnCode(sab, 0);	
	}


	getSongInfoMeta() {
		return {title: String
				};
	}
	getNumberTraceStreams(sab) {
		if (!this.isAdapterReady()) return 0;
		var ret= this.Module.ccall('emu_number_trace_streams', 'number');	

		this.setReturnCode(sab, ret);	
	}

	getMaxPosition(sab) {
		if (!this.isAdapterReady()) { this.setReturnCode(sab, 0); return; }
		var ret= this.Module.ccall('emu_get_max_position', 'number');
		this.setReturnCode(sab, ret);
	}

	getSampleRate(sab) {
		var ret= this.Module.ccall('emu_get_sample_rate', 'number');
		this.setReturnCode(sab, ret);
	}
	
	// copy the latest buffer into the respective shared bufs
	pushTraceStreamData() {
		let outBuffers = this.scopeBuffersFloat32View[this.scopeDoubleBufferToggle];
		
		var n= this.Module.ccall('emu_number_trace_streams', 'number');

		var ret = this.Module.ccall('emu_get_trace_streams', 'number');			
		var array = this.Module.HEAP32.subarray(ret>>2, (ret>>2)+n);
		
		for (let i= 0; i<n; i++) {
			let inputBuf = array[i] >> 2; 	// float array in Emscripten memory
			let outBuffer = outBuffers[i];
			
			for (let j = 0; j<128; j++) {
				outBuffer[j] = this.Module.HEAPF32[inputBuf+j];		// FIXME depending on backed a conversion is needed here
			}			
		}
			
		// notify Node side
		this.port.postMessage({ 
								message: 'audioRendered',
								scopeBufIdx: this.scopeDoubleBufferToggle

							});		
		this.scopeDoubleBufferToggle = this.scopeDoubleBufferToggle ? 0 : 1;	// use the other set next time		
	}
	
	
	// how the 16 channels are currently mapped to the 64 voices
	getVoiceMapping() {
		var n= 16;
		var result=[];

		var ret = this.Module.ccall('emu_get_voice_map', 'number');			
		var array = this.Module.HEAP32.subarray(ret>>2, (ret>>2)+n);
		
		for (var i= 0; i<n; i++) {			
			result.push(array[i]);	// int
		}

		return result;
	}
	fillBlank(bufL, bufR) {
		for (let i = 0;  i < bufL.length; i++) {
			bufL[i]= 0;
			bufR[i]= 0;					
		}
	}
	
	// silence detection stuff
	detectSilence(elapsedTime, s) {
		this._currentPlaytime += elapsedTime;
		
		this.trackSilence(s);
		
		if ((this._silenceStarttime > 0) && ((this._currentPlaytime - this._silenceStarttime) >= this._silenceTimeout*this.sampleRate ) && (this._silenceTimeout >0)) {
			this.paused = true;	// stop playback (or this will retrigger again and again before new song is started)
			// _silenceStarttime = sample position where silence began = end of music
			var realDur = (this.sampleRate > 0 && this._silenceStarttime > 0)
				? this._silenceStarttime / this.sampleRate : 0;
			this.port.postMessage({ message: 'songEnded', duration: realDur });
		}
	}
	
	trackSilence(sumOut) {
		if (this._silenceStarttime == 0) {	// i.e. song has been playing
			if (sumOut == 0) {	// silence detected
				this._silenceStarttime= this._currentPlaytime;
			}
		} else if (sumOut > 0) {	// i.e. false alarm or very start of playback
			this._silenceStarttime= 0;
		}
	}

	
	process(inputs, outputs) {
				
		if (this.ready) {
			const output = outputs[0];

			// always stereo
			let bufL  = output[0];
			let bufR  = output[1];

			
			if (!this.paused) {
				
				// FIXME not all backends produce interleaved stereo data
				let r = this.computeAudioSamples();
				if (!r) {
					let input= this.getAudioBuffer();
					let len= this.getAudioBufferLength();
					
					if (bufL.length != len) {
						console.log("error: "+bufL.length +" "+ len);
					}
					else {
						var s = 0;
						for (let i = 0;  i < bufL.length; i++) {
							// FIXME not all backends produce signed 16-bit ints
							bufL[i]= (this.Module.HEAP16[input+ i*2 ])/0x8000;
							bufR[i]= (this.Module.HEAP16[input+ i*2 +1])/0x8000;
							
							s+= Math.abs(bufL[i]) + Math.abs(bufR[i]);
						}
						
						// potential problem: when the UI side gets the notification the
						// shared buffer context may not have been "sent" yet
						this.pushTraceStreamData();
						
						this.detectSilence(128, s);
					}
				}
				else if (r < 0) {
				// FIXME: handle -1, i.e. load-file-on-demand sceanario
				}
				else {
					// song end — use _currentPlaytime as duration
					this.fillBlank(bufL, bufR);
					this.paused = true;
					var dur2 = this.sampleRate > 0 ? this._currentPlaytime / this.sampleRate : 0;
					this.port.postMessage({ message: 'songEnded', duration: dur2 });
				}				
			} 
			else {
				this.fillBlank(bufL, bufR);
			}
			
			
		}
		return true;
	}
}

registerProcessor('v2m-processor', V2MProcessor);

/////////////////////////////// part 4 end /////////////////////////////////////////
